def adjust_contrast(image, contrast_factor):
  adjusted_image = []
  for pixel in image:
    adjusted_pixel = pixel * contrast_factor
    if adjusted_pixel > 255:
      adjusted_pixel = 255
    elif adjusted_pixel < 0:
      adjusted_pixel = 0
    adjusted_image.append(adjusted_pixel)
  return adjusted_image

#include <stdio.h>

void invert_image(unsigned char *image, int size) {
  for (int i = 0; i < size; i++) {
    image[i] = 255 - image[i];
  }
}
